from flask import Flask, request, jsonify
import uuid
import hashlib

app = Flask(__name__)

auth_codes = {}

def generate_code():
    return str(uuid.uuid4())

@app.route('/authorize', methods=['POST'])
def authorize():
    client_id = request.json.get('client_id')
    redirect_uri = request.json.get('redirect_uri')
    response_type = request.json.get('response_type')
    scope = request.json.get('scope')
    state = request.json.get('state')

    if not (client_id and redirect_uri and response_type and scope):
        return jsonify({'error': 'missing_required_parameter'}), 400

    code = generate_code()
    auth_codes[code] = client_id
    return jsonify({'code': code, 'state': state}), 200

@app.route('/token', methods=['POST'])
def token():
    code = request.json.get('code')
    redirect_uri = request.json.get('redirect_uri')
    grant_type = request.json.get('grant_type')

    if not (code and redirect_uri and grant_type):
        return jsonify({'error': 'missing_required_parameter'}), 400

    if code in auth_codes:
        client_id = auth_codes[code]
        del auth_codes[code]

        # Simulate token generation
        access_token = hashlib.sha256(f'{client_id}{code}'.encode()).hexdigest()
        return jsonify({
            'access_token': access_token,
            'token_type': 'bearer',
            'expires_in': 3600
        }), 200

    return jsonify({'error': 'invalid_code'}), 401

if __name__ == '__main__':
    app.run(debug=True)